"""Render calibration results as a Python module the framework can load.

The output of :func:`bench.calibrate.calibrate_default_evaluators` is a
nested Python dict. To make it consumable by
``structural_computing.calibration.apply_calibration()``, we write it
as a Python module exposing a top-level ``CALIBRATED_COSTS`` constant.

The shape of the output module is intentionally simple so the
framework can load it without pulling in the bench package:

    # auto-generated by structural-computing-bench, do not edit by hand
    CALIBRATED_COSTS = {
        ("T0", "count_solutions"): {"model": "power_law", "params": (1.2e-6, 2.97), "rms": 0.08},
        ("T2", "matching_count"):  {"model": "power_law", "params": (5.0e-7, 3.51), "rms": 0.05},
        ...
    }
    METADATA = {
        "generated_at": "2026-05-28T12:34:56",
        "machine":      "x86_64-Windows-10",
        "bench_version": "0.1.0a1",
    }
"""
from __future__ import annotations

import datetime
import platform
from typing import Any, Dict, Tuple


def render_calibration_module(calibration: Dict[Tuple[str, str], Dict[str, Any]],
                                *,
                                bench_version: str = "unknown",
                                ) -> str:
    """Return the Python source for a calibration module.

    The returned string is ready to be written to a `.py` file and
    imported by the framework. It contains a single top-level
    ``CALIBRATED_COSTS`` dict plus a ``METADATA`` dict carrying
    timestamp + machine info for traceability.

    Args:
      calibration: the output of :func:`calibrate_default_evaluators`.
      bench_version: the version string of the bench package that
        produced the data (for the metadata block).

    Returns:
      Python source as a string (UTF-8). Write directly to a `.py` file.
    """
    lines = [
        "# Auto-generated by structural-computing-bench. Do not edit by hand.",
        "# To regenerate: `python scripts/run_calibration.py --out <path>`.",
        "",
        "CALIBRATED_COSTS = {",
    ]
    for key in sorted(calibration.keys()):
        result = calibration[key]
        params = result["params"]
        # Skip include_curves payloads in the rendered output (they're
        # large; the metadata + params are what apply_calibration cares
        # about).
        compact = {
            "model": result["model"],
            "params": (float(params[0]), float(params[1])),
            "rms": float(result["rms"]),
        }
        lines.append(f"    {key!r}: {compact!r},")
    lines.append("}")
    lines.append("")
    metadata = {
        "generated_at": datetime.datetime.now(datetime.timezone.utc).isoformat(timespec="seconds"),
        "machine": f"{platform.machine()}-{platform.system()}-{platform.release()}",
        "python":  platform.python_version(),
        "bench_version": bench_version,
    }
    lines.append(f"METADATA = {metadata!r}")
    lines.append("")
    return "\n".join(lines)
